const MAX_BUFFER = 1 << 20;        // 1 MB ceiling per connection

function safeSend(ws, data) {
  if (ws.bufferedAmount > MAX_BUFFER) {
    // Slow client: do not pile on. Drop, coalesce, or disconnect.
    ws.close(1013, 'try again later');   // 1013 = Try Again Later
    return false;
  }
  ws.send(data);
  return true;
}

