import crypto from 'crypto';

const WS_GUID = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11';

function computeAccept(secWebSocketKey) {
  return crypto
    .createHash('sha1')
    .update(secWebSocketKey + WS_GUID)   // concatenate the received key string + GUID
    .digest('base64');                   // base64 of the raw 20-byte SHA-1 digest
}

// RFC 6455 worked example:
const accept = computeAccept('dGhlIHNhbXBsZSBub25jZQ==');
console.assert(accept === 's3pPLMBiTxaQ9kYGzzhZRbK+xOo=', accept);
console.log(accept); // s3pPLMBiTxaQ9kYGzzhZRbK+xOo=

const MAX_BUFFER = 1 << 20;   // 1 MB per-connection ceiling

function broadcast(clients, message) {
  const payload = typeof message === 'string' ? message : JSON.stringify(message);
  for (const ws of clients) {
    if (ws.readyState !== ws.OPEN) continue;        // skip CONNECTING/CLOSING/CLOSED
    if (ws.bufferedAmount > MAX_BUFFER) {            // slow consumer: do not pile on
      ws.close(1013, 'too slow');                   // 1013 Try Again Later
      continue;
    }
    ws.send(payload);
  }
}

// Heartbeat: detect and reclaim half-open connections.
function setupHeartbeat(wss, intervalMs = 30000) {
  wss.on('connection', (ws) => {
    ws.isAlive = true;
    ws.on('pong', () => { ws.isAlive = true; });    // peer answered our ping
  });
  const timer = setInterval(() => {
    for (const ws of wss.clients) {
      if (ws.isAlive === false) { ws.terminate(); continue; }  // missed last pong
      ws.isAlive = false;
      ws.ping();                                     // expect a pong before next tick
    }
  }, intervalMs);
  wss.on('close', () => clearInterval(timer));
  return timer;
}
